package com.example.prototypeauth;

import android.content.Intent;
import android.os.Bundle;
import android.text.TextUtils;
import android.widget.Button;
import android.widget.EditText;
import android.widget.Toast;

import androidx.appcompat.app.AppCompatActivity;

public class LoginActivity extends AppCompatActivity {

    private EditText emailEditText;
    private EditText passwordEditText;
    private Button loginButton;

    private SessionManager sessionManager;
    private AuthRepository authRepository;

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);

        sessionManager = new SessionManager(this);
        authRepository = new AuthRepository();

        if (sessionManager.isLoggedIn()) {
            navigateToHome();
            finish();
            return;
        }

        setContentView(R.layout.activity_login);

        emailEditText = findViewById(R.id.etEmail);
        passwordEditText = findViewById(R.id.etPassword);
        loginButton = findViewById(R.id.btnLogin);

        loginButton.setOnClickListener(v -> attemptLogin());
    }

    private void attemptLogin() {
        String email = emailEditText.getText().toString().trim();
        String password = passwordEditText.getText().toString();

        if (TextUtils.isEmpty(email)) {
            emailEditText.setError("Email required");
            emailEditText.requestFocus();
            return;
        }

        if (TextUtils.isEmpty(password)) {
            passwordEditText.setError("Password required");
            passwordEditText.requestFocus();
            return;
        }

        authRepository.login(email, password, new AuthRepository.LoginCallback() {
            @Override
            public void onSuccess(String authToken) {
                sessionManager.saveSession(email, authToken);
                Toast.makeText(LoginActivity.this, "Login successful", Toast.LENGTH_SHORT).show();
                navigateToHome();
                finish();
            }

            @Override
            public void onError(String message) {
                Toast.makeText(LoginActivity.this, message, Toast.LENGTH_SHORT).show();
            }
        });
    }

    private void navigateToHome() {
        startActivity(new Intent(this, HomeActivity.class));
    }
}

package com.example.prototypeauth;

import android.content.Intent;
import android.os.Bundle;
import android.widget.Button;
import android.widget.TextView;

import androidx.appcompat.app.AppCompatActivity;

public class HomeActivity extends AppCompatActivity {

    private TextView welcomeTextView;
    private TextView tokenTextView;
    private Button logoutButton;

    private SessionManager sessionManager;

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);

        sessionManager = new SessionManager(this);

        if (!sessionManager.isLoggedIn()) {
            navigateToLogin();
            finish();
            return;
        }

        setContentView(R.layout.activity_home);

        welcomeTextView = findViewById(R.id.tvWelcome);
        tokenTextView = findViewById(R.id.tvToken);
        logoutButton = findViewById(R.id.btnLogout);

        welcomeTextView.setText("Welcome, " + sessionManager.getEmail());
        tokenTextView.setText("Token: " + sessionManager.getAuthToken());

        logoutButton.setOnClickListener(v -> {
            sessionManager.clearSession();
            navigateToLogin();
            finish();
        });
    }

    private void navigateToLogin() {
        startActivity(new Intent(this, LoginActivity.class));
    }
}

